using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Scoring;

namespace Contoso.Scoring.Tests;

[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calc = new();
    private const double Tolerance = 0.001;

    // --- CalculatePercentage ---

    [TestMethod]
    public void CalculatePercentage_PerfectScore_Returns100()
    {
        Assert.AreEqual(100.0, _calc.CalculatePercentage(10, 10), Tolerance);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroCorrect_Returns0()
    {
        Assert.AreEqual(0.0, _calc.CalculatePercentage(0, 10), Tolerance);
    }

    [TestMethod]
    public void CalculatePercentage_PartialScore_ReturnsExpected()
    {
        Assert.AreEqual(75.0, _calc.CalculatePercentage(3, 4), Tolerance);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(0, -1));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(11, 10));
    }

    // --- GetGrade boundary tests ---

    [DataTestMethod]
    [DataRow(100.0, "A")]
    [DataRow(90.0,  "A")]  // boundary: exactly 90
    [DataRow(89.999, "B")] // just below A
    [DataRow(80.0,  "B")]  // boundary: exactly 80
    [DataRow(79.999, "C")] // just below B
    [DataRow(70.0,  "C")]
    [DataRow(69.999, "D")] // just below C
    [DataRow(60.0,  "D")]
    [DataRow(59.999, "F")] // just below D
    [DataRow(0.0,   "F")]
    public void GetGrade_AtBoundaries_ReturnsCorrectGrade(
        double percentage, string expected)
    {
        Assert.AreEqual(expected, _calc.GetGrade(percentage));
    }

    // --- NormalizeScore ---

    [TestMethod]
    public void NormalizeScore_HalfOfMax_Returns50()
    {
        Assert.AreEqual(50.0, _calc.NormalizeScore(25, 50), Tolerance);
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_ClampedTo100()
    {
        double result = _calc.NormalizeScore(120, 100);
        Assert.AreEqual(100.0, result, Tolerance);
    }

    [TestMethod]
    public void NormalizeScore_ZeroRaw_Returns0()
    {
        Assert.AreEqual(0.0, _calc.NormalizeScore(0, 100), Tolerance);
    }

    [TestMethod]
    public void NormalizeScore_ResultIsWithinValidRange()
    {
        double result = _calc.NormalizeScore(42, 50);
        // No Assert.IsInRange — use Assert.IsTrue for range checks
        Assert.IsTrue(result >= 0.0 && result <= 100.0,
            $"Expected 0–100 but got {result}");
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(-1, 100));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(50, 0));
    }
}

